import { tags } from 'decantr/tags';
import { createSignal, onMount } from 'decantr/state';
import { css } from 'decantr/css';

code.example:
function TerminalEmulator({ onCommand, initialOutput = [] }) {
  const { div, pre, input, span } = tags;
  const [output, setOutput] = createSignal(initialOutput);
  const [command, setCommand] = createSignal('');
  const [history, setHistory] = createSignal([]);
  const [historyIndex, setHistoryIndex] = createSignal(-1);
  let outputRef, inputRef;

  const handleSubmit = (e) => {
    if (e.key === 'Enter' && command().trim()) {
      const cmd = command();
      setHistory([...history(), cmd]);
      setOutput([...output(), { type: 'input', text: `$ ${cmd}` }]);
      const result = onCommand(cmd);
      if (result) setOutput([...output(), { type: 'output', text: result }]);
      setCommand('');
      setHistoryIndex(-1);
      setTimeout(() => outputRef?.scrollTo({ top: outputRef.scrollHeight }), 0);
    } else if (e.key === 'ArrowUp') {
      const idx = historyIndex() + 1;
      if (idx < history().length) {
        setHistoryIndex(idx);
        setCommand(history()[history().length - 1 - idx]);
      }
    } else if (e.key === 'ArrowDown') {
      const idx = historyIndex() - 1;
      if (idx >= 0) {
        setHistoryIndex(idx);
        setCommand(history()[history().length - 1 - idx]);
      } else {
        setHistoryIndex(-1);
        setCommand('');
      }
    }
  };

  onMount(() => inputRef?.focus());

  return div({ class: css('term-panel _flex _col _hfull _p2') },
    pre({ ref: (el) => outputRef = el, class: css('_flex1 _overflow[auto] _m0 _whitespace[pre-wrap]') },
      ...output().map(line =>
        div({ class: line.type === 'input' ? css('_fgmuted') : '' }, line.text)
      )
    ),
    div({ class: css('_flex _aic _gap1 _pt2 _borderT _bordercolor[#333]') },
      span({ class: css('term-glow') }, '$'),
      input({
        ref: (el) => inputRef = el,
        type: 'text',
        value: command,
        oninput: (e) => setCommand(e.target.value),
        onkeydown: handleSubmit,
        class: css('_flex1 _bg[transparent] _border0 _outline0 _fggreen _mono term-blink'),
        spellcheck: false,
        autocomplete: 'off'
      })
    )
  );
}

function ReadonlyTerminal({ lines }) {
  const { div, pre } = tags;
  return div({ class: css('term-panel _hfull _p2 _overflow[auto]') },
    pre({ class: css('_m0 _whitespace[pre-wrap]') },
      ...lines.map(line => div({}, line))
    )
  );
}

function SplitTerminal({ output, onCommand }) {
  const { div } = tags;
  return div({ class: css('_grid _hfull'), style: 'grid-template-rows: 1fr auto' },
    ReadonlyTerminal({ lines: output }),
    TerminalInput({ onCommand })
  );
}

